def assess(record: dict) -> str:
    required = {"case_id", 'tp', 'fp', 'fn', 'accuracy_only'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if not (record["accuracy_only"] is True) else "REJECT_ACCURACY_ONLY"

valid = {"case_id": "CASO-LIM-034-1A", **{'tp': 1, 'fp': 1, 'fn': 0, 'accuracy_only': False}}
invalid = {"case_id": "CASO-LIM-034-1A", **{'tp': 0, 'fp': 0, 'fn': 0, 'accuracy_only': True}}
incomplete = {**valid}
incomplete.pop("tp")
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

def decide(record: dict) -> str:
    required = {"case_id", 'tp', 'fp', 'fn', 'accuracy_only'}
    missing = sorted(required - record.keys())
    if missing:
        return "REQUEST_CONFUSION"
    bad = (record["accuracy_only"] is True)
    if bad:
        return "REJECT_ACCURACY_ONLY"
    return "CONTINUE"

valid = {"case_id": "CASO-LIM-034-1A", **{'tp': 1, 'fp': 1, 'fn': 0, 'accuracy_only': False}}
invalid = dict(valid)
invalid["accuracy_only"] = True
uncertain = {k: v for k, v in valid.items() if k != "accuracy_only"}
print(decide(valid), decide(invalid), decide(uncertain))

